import './Badge.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import type { BadgeProps } from './Badge.types';

export const Badge: FC<BadgeProps> = ({
	children,
	type = 'secondary',
	semantic = 'info',
	icon,
	dot = false,
	className,
	dataTestId = 'Badge',
	...props
}) => {
	const showIcon = !dot && icon;

	const semanticClassMap: Record<string, string> = {
		danger: 'error',
	};
	const semanticToken = semanticClassMap[semantic] ?? semantic;

	return (
		<span
			data-testid={dataTestId}
			className={classNames(
				'dsb_badge',
				`dsb_badge__${type}`,
				`dsb_badge__${semanticToken}`,
				{
					'dsb_badge__has-dot': dot,
					'dsb_badge__has-icon': !!showIcon,
				},
				className,
			)}
			{...props}
		>
			{dot && <span className="dsb_badge__dot" aria-hidden="true" />}
			{showIcon && (
				<span className="dsb_badge__icon" aria-hidden="true">
					<Icon iconName={icon} size="small" />
				</span>
			)}
			<span className="dsb_badge__text">{children}</span>
		</span>
	);
};
